// Tap-to-preview for touch devices: the first tap on a ride line shows its
// stats chip and a second tap follows the link to Strava. This is the only
// scripted behavior left in the backdrop — rendering, animation, hover/focus
// chips, and positioning are all static SVG/CSS generated by
// scripts/render-backdrop.mjs.
(function () {
  "use strict";

  const container = document.querySelector(".ride-backdrop");
  if (!container) return;
  const links = [...container.querySelectorAll("svg a")];
  const chips = [...container.querySelectorAll(".ride-chip")];
  const touchOnly = matchMedia("(hover: none)");
  let active = null; // [link, chip]

  function clearActive() {
    if (!active) return;
    active[0].classList.remove("active");
    active[1]?.classList.remove("active");
    active = null;
  }

  links.forEach((link, i) => {
    link.addEventListener("click", (e) => {
      if (touchOnly.matches && active?.[0] !== link) {
        e.preventDefault();
        clearActive();
        active = [link, chips[i]];
        link.classList.add("active");
        chips[i]?.classList.add("active");
      }
    });
  });

  document.addEventListener("pointerdown", (e) => {
    if (active && !e.target.closest(".ride-backdrop a")) clearActive();
  });
})();
